option.value:
"use client";

import { ChangeEvent, FormEvent, useCallback, useEffect, useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, LineChart, Line, ResponsiveContainer } from "recharts";

type DashboardPayload = {
  metrics: {
    totalContacts: number;
    sentCount: number;
    pendingCount: number;
    failedCount: number;
  };
  pagination: {
    page: number;
    pageSize: number;
    totalItems: number;
    totalPages: number;
    search: string;
  };
  analytics: {
    sentByChannel: Array<{ label: string; key: string; count: number }>;
    sentByHour: Array<{ hour: string; count: number }>;
    sentByDay: Array<{ day: string; count: number }>;
    sentByWeek: Array<{ week: string; count: number }>;
    sentByCity: Array<{ city: string; count: number }>;
  };
  avocats: Array<{
    id: string;
    fullName: string;
    email: string | null;
    phone: string | null;
    city: string | null;
    firmName: string | null;
    preferredContactMethod: "email" | "whatsapp" | "both";
  }>;
  logs: Array<{
    id: string;
    lawyerName: string;
    email: string;
    status: "pending" | "sent" | "failed";
    attempts: number;
    lastError: string | null;
    sentAt: string | null;
    campaignName: string;
    city: string;
  }>;
};

type ApiResult = {
  message?: string;
  processed?: number;
  sent?: number;
  failed?: number;
  resetCount?: number;
  created?: number;
  skipped?: number;
  errors?: string[];
};

type FormState = {
  full_name: string;
  email: string;
  phone: string;
  city: string;
  firm_name: string;
  preferred_contact_method: "email" | "whatsapp" | "both";
};

const emptyForm: FormState = {
  full_name: "",
  email: "",
  phone: "",
  city: "",
  firm_name: "",
  preferred_contact_method: "email"
};

function formatDate(value: string | null) {
  if (!value) {
    return "-";
  }

  return new Intl.DateTimeFormat("fr-FR", {
    dateStyle: "medium",
    timeStyle: "short"
  }).format(new Date(value));
}

export function DashboardClient() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const currentStatus = searchParams.get("status") || "all";
  const currentSearch = searchParams.get("search") || "";
  const currentPage = Number(searchParams.get("page") || "1");
  const [data, setData] = useState<DashboardPayload | null>(null);
  const [loading, setLoading] = useState(true);
  const [busyKey, setBusyKey] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);
  const [form, setForm] = useState<FormState>(emptyForm);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [searchInput, setSearchInput] = useState(currentSearch);

  const loadDashboard = useCallback(async () => {
    setLoading(true);

    try {
      const params = new URLSearchParams();

      if (currentStatus !== "all") {
        params.set("status", currentStatus);
      }

      if (currentSearch) {
        params.set("search", currentSearch);
      }

      if (currentPage > 1) {
        params.set("page", String(currentPage));
      }

      const response = await fetch(`/api/dashboard${params.toString() ? `?${params.toString()}` : ""}`, {
        cache: "no-store"
      });

      if (!response.ok) {
        throw new Error("Unable to load dashboard data.");
      }

      const payload = (await response.json()) as DashboardPayload;
      setData(payload);
    } catch (error) {
      setMessage(error instanceof Error ? error.message : "Unable to load dashboard data.");
    } finally {
      setLoading(false);
    }
  }, [currentPage, currentSearch, currentStatus]);

  useEffect(() => {
    void loadDashboard();
  }, [loadDashboard]);

  useEffect(() => {
    setSearchInput(currentSearch);
  }, [currentSearch]);

  function updateParams(next: { status?: string; search?: string; page?: number }) {
    const params = new URLSearchParams(searchParams.toString());

    if (next.status !== undefined) {
      if (next.status === "all") {
        params.delete("status");
      } else {
        params.set("status", next.status);
      }
    }

    if (next.search !== undefined) {
      if (next.search.trim()) {
        params.set("search", next.search.trim());
      } else {
        params.delete("search");
      }
    }

    if (next.page !== undefined) {
      if (next.page > 1) {
        params.set("page", String(next.page));
      } else {
        params.delete("page");
      }
    }

    router.replace(`/dashboard${params.toString() ? `?${params.toString()}` : ""}`);
  }

  function onFormChange(event: ChangeEvent<HTMLInputElement | HTMLSelectElement>) {
    const { name, value } = event.target;
    setForm((current) => ({ ...current, [name]: value }));
  }

  function resetForm() {
    setForm(emptyForm);
    setEditingId(null);
  }

  async function runAction(path: string, actionKey: string, options?: { method?: string; body?: unknown }) {
    setBusyKey(actionKey);
    setMessage(null);

    try {
      const response = await fetch(path, {
        method: options?.method || "POST",
        headers: options?.body
          ? {
              "Content-Type": "application/json"
            }
          : undefined,
        body: options?.body ? JSON.stringify(options.body) : undefined
      });

      const payload = (await response.json()) as ApiResult & { error?: string };

      if (!response.ok) {
        throw new Error(payload.error || "Request failed.");
      }

      if (actionKey === "logout") {
        router.replace("/login");
        router.refresh();
        return true;
      }

      setMessage(payload.message || "Action completed successfully.");
      await loadDashboard();
      return true;
    } catch (error) {
      setMessage(error instanceof Error ? error.message : "Request failed.");
      return false;
    } finally {
      setBusyKey(null);
    }
  }

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();

    let success = false;

    if (editingId) {
      success = await runAction(`/api/avocats/${editingId}`, "save-avocat", {
        method: "PUT",
        body: form
      });
    } else {
      success = await runAction("/api/avocats", "add-avocat", {
        method: "POST",
        body: form
      });
    }

    if (success) {
      resetForm();
    }
  }

  async function handleImport(event: ChangeEvent<HTMLInputElement>) {
    const file = event.target.files?.[0];

    if (!file) {
      return;
    }

    setBusyKey("import");
    setMessage(null);

    try {
      const fileText = await file.text();
      const payload = JSON.parse(fileText) as unknown;
      const response = await fetch("/api/avocats/import", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(payload)
      });
      const result = (await response.json()) as ApiResult & { error?: string };

      if (!response.ok) {
        throw new Error(result.error || "Unable to import avocats.");
      }

      const importMessage = [result.message, result.errors?.slice(0, 3).join(" | ")]
        .filter(Boolean)
        .join(" ");
      setMessage(importMessage);
      await loadDashboard();
    } catch (error) {
      setMessage(error instanceof Error ? error.message : "Unable to import avocats.");
    } finally {
      event.target.value = "";
      setBusyKey(null);
    }
  }

  async function handleExport() {
    setBusyKey("export");
    setMessage(null);

    try {
      const response = await fetch("/api/avocats/export", {
        method: "GET"
      });

      if (!response.ok) {
        const payload = (await response.json()) as { error?: string };
        throw new Error(payload.error || "Unable to export avocats.");
      }

      const blob = await response.blob();
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = "avocats-export.json";
      document.body.appendChild(link);
      link.click();
      link.remove();
      URL.revokeObjectURL(url);
      setMessage("Avocats exported successfully.");
    } catch (error) {
      setMessage(error instanceof Error ? error.message : "Unable to export avocats.");
    } finally {
      setBusyKey(null);
    }
  }

  function startEdit(avocat: DashboardPayload["avocats"][number]) {
    setEditingId(avocat.id);
    setForm({
      full_name: avocat.fullName,
      email: avocat.email || "",
      phone: avocat.phone || "",
      city: avocat.city || "",
      firm_name: avocat.firmName || "",
      preferred_contact_method: avocat.preferredContactMethod
    });
  }

  return (
    <div className="dashboard-layout">
      <header className="dashboard-nav">
        <div className="nav-brand">
          <h1 className="page-title">Outreach Dashboard 2026</h1>
          <span className="hero-note">AI-Powered Campaign Management</span>
        </div>
        <div className="nav-actions">
          <button
            className="button button-secondary"
            disabled={loading}
            onClick={() => void loadDashboard()}
            type="button"
          >
            {loading ? "Refreshing..." : "Refresh"}
          </button>
          <button
            className="button button-primary"
            disabled={busyKey !== null}
            onClick={() => void runAction("/api/send", "send")}
            type="button"
          >
            {busyKey === "send" ? "Sending..." : "Send Now"}
          </button>
          <button
            className="button button-danger"
            disabled={busyKey !== null}
            onClick={() => void runAction("/api/retry-failed", "retry")}
            type="button"
          >
            {busyKey === "retry" ? "Retrying..." : "Retry Failed"}
          </button>
          <button
            className="button button-secondary"
            disabled={busyKey !== null}
            onClick={() => void runAction("/api/auth/logout", "logout")}
            type="button"
          >
            {busyKey === "logout" ? "Logging out..." : "Logout"}
          </button>
        </div>
      </header>

      <main className="dashboard-main">
        <section className="metrics-section">
          <h2 className="section-title">Key Metrics</h2>
          <div className="metrics-grid">
            <article className="metric-card glass">
              <p className="metric-label">Total contacts</p>
              <h2 className="metric-value">{data?.metrics.totalContacts ?? "-"}</h2>
            </article>
            <article className="metric-card glass">
              <p className="metric-label">Sent</p>
              <h2 className="metric-value">{data?.metrics.sentCount ?? "-"}</h2>
            </article>
            <article className="metric-card glass">
              <p className="metric-label">Pending</p>
              <h2 className="metric-value">{data?.metrics.pendingCount ?? "-"}</h2>
            </article>
            <article className="metric-card glass">
              <p className="metric-label">Failed</p>
              <h2 className="metric-value">{data?.metrics.failedCount ?? "-"}</h2>
            </article>
          </div>
        </section>

        <section className="analytics-section">
          <h2 className="section-title">Analytics</h2>
          <div className="charts-grid">
            <article className="chart-card glass">
              <h3>Sent by Channel</h3>
              <div className="chart-container">
                <ResponsiveContainer width="100%" height={300}>
                  <PieChart>
                    <Pie
                      data={data?.analytics.sentByChannel || []}
                      cx="50%"
                      cy="50%"
                      labelLine={false}
                      outerRadius={80}
                      fill="#8884d8"
                      dataKey="count"
                    >
                      {data?.analytics.sentByChannel.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={['#007bff', '#28a745', '#ffc107'][index % 3]} />
                      ))}
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </article>

            <article className="chart-card glass">
              <h3>Sent by Hour</h3>
              <div className="chart-container">
                <ResponsiveContainer width="100%" height={300}>
                  <LineChart data={data?.analytics.sentByHour || []}>
                    <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                    <XAxis dataKey="hour" stroke="var(--muted)" />
                    <YAxis stroke="var(--muted)" />
                    <Tooltip contentStyle={{ backgroundColor: 'var(--bg-elevated)', border: '1px solid var(--border)' }} />
                    <Line type="monotone" dataKey="count" stroke="#007bff" strokeWidth={2} dot={{ fill: '#007bff' }} />
                  </LineChart>
                </ResponsiveContainer>
              </div>
            </article>

            <article className="chart-card glass">
              <h3>Sent by Day</h3>
              <div className="chart-container">
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={data?.analytics.sentByDay || []}>
                    <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                    <XAxis dataKey="day" stroke="var(--muted)" />
                    <YAxis stroke="var(--muted)" />
                    <Tooltip contentStyle={{ backgroundColor: 'var(--bg-elevated)', border: '1px solid var(--border)' }} />
                    <Bar dataKey="count" fill="#007bff" />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </article>

            <article className="chart-card glass">
              <h3>Sent by Week</h3>
              <div className="chart-container">
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={data?.analytics.sentByWeek || []}>
                    <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                    <XAxis dataKey="week" stroke="var(--muted)" />
                    <YAxis stroke="var(--muted)" />
                    <Tooltip contentStyle={{ backgroundColor: 'var(--bg-elevated)', border: '1px solid var(--border)' }} />
                    <Bar dataKey="count" fill="#28a745" />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </article>

            <article className="chart-card glass">
              <h3>Sent by City</h3>
              <div className="chart-container">
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={data?.analytics.sentByCity || []} layout="horizontal">
                    <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                    <XAxis type="number" stroke="var(--muted)" />
                    <YAxis dataKey="city" type="category" stroke="var(--muted)" width={80} />
                    <Tooltip contentStyle={{ backgroundColor: 'var(--bg-elevated', border: '1px solid var(--border)' }} />
                    <Bar dataKey="count" fill="#ffc107" />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </article>
          </div>
        </section>

        <section className="management-section">
          <h2 className="section-title">Contact Management</h2>
          <div className="panel-grid">
            <article className="panel-card glass">
              <h3>{editingId ? "Update avocat" : "Add avocat"}</h3>
              <p className="helper-text">
                Manage one contact at a time here, or use JSON import/export for bulk operations.
              </p>

              <form className="form-grid" onSubmit={handleSubmit} style={{ marginTop: 18 }}>
                <div className="full-span">
                  <label className="label" htmlFor="full_name">
                    Full name
                  </label>
                  <input
                    id="full_name"
                    className="input"
                    name="full_name"
                    onChange={onFormChange}
                    required
                    value={form.full_name}
                  />
                </div>

                <div>
                  <label className="label" htmlFor="email">
                    Email
                  </label>
                  <input
                    id="email"
                    className="input"
                    name="email"
                    onChange={onFormChange}
                    type="email"
                    value={form.email}
                  />
                </div>

                <div>
                  <label className="label" htmlFor="phone">
                    Phone
                  </label>
                  <input
                    id="phone"
                    className="input"
                    name="phone"
                    onChange={onFormChange}
                    value={form.phone}
                  />
                </div>

                <div>
                  <label className="label" htmlFor="city">
                    City
                  </label>
                  <input
                    id="city"
                    className="input"
                    name="city"
                    onChange={onFormChange}
                    value={form.city}
                  />
                </div>

                <div>
                  <label className="label" htmlFor="firm_name">
                    Firm name
                  </label>
                  <input
                    id="firm_name"
                    className="input"
                    name="firm_name"
                    onChange={onFormChange}
                    value={form.firm_name}
                  />
                </div>

                <div className="full-span">
                  <label className="label" htmlFor="preferred_contact_method">
                    Preferred contact
                  </label>
                  <select
                    id="preferred_contact_method"
                    className="select"
                    name="preferred_contact_method"
                    onChange={onFormChange}
                    value={form.preferred_contact_method}
                  >
                    <option value="email">email</option>
                    <option value="whatsapp">whatsapp</option>
                    <option value="both">both</option>
                  </select>
                </div>

                <div className="full-span action-row" style={{ marginTop: 8 }}>
                  <button className="button button-primary" disabled={busyKey !== null} type="submit">
                    {busyKey === "add-avocat" || busyKey === "save-avocat"
                      ? "Saving..."
                      : editingId
                        ? "Update avocat"
                        : "Add avocat"}
                  </button>
                  {editingId ? (
                    <button className="button button-secondary" onClick={resetForm} type="button">
                      Cancel edit
                    </button>
                  ) : null}
                </div>
              </form>
            </article>

            <article className="panel-card glass">
              <h3>Import / export JSON</h3>
              <p className="helper-text">
                Import Apify raw JSON or export the current avocat list.
              </p>

              <div className="action-row" style={{ marginTop: 18 }}>
                <label className="button button-secondary" htmlFor="avocat-import">
                  {busyKey === "import" ? "Importing..." : "Import JSON"}
                </label>
                <input
                  id="avocat-import"
                  accept=".json,application/json"
                  className="file-input"
                  disabled={busyKey !== null}
                  onChange={handleImport}
                  style={{ display: "none" }}
                  type="file"
                />
                <button
                  className="button button-secondary"
                  disabled={busyKey !== null}
                  onClick={() => void handleExport()}
                  type="button"
                >
                  {busyKey === "export" ? "Exporting..." : "Export JSON"}
                </button>
              </div>

              <p className="helper-text" style={{ marginTop: 16 }}>
                Use the searchable table below to update, delete, or send outreach for a specific
                avocat.
              </p>
            </article>
          </div>
        </section>

        <section className="contacts-section">
          <div className="table-card glass">
            <div style={{ padding: 18 }}>
              <div className="toolbar">
                <div>
                  <h3>Avocats</h3>
                  <p className="helper-text">{data?.pagination.totalItems ?? 0} contact(s) found.</p>
                </div>

                <form
                  className="search-row"
                  onSubmit={(event) => {
                    event.preventDefault();
                    updateParams({ search: searchInput, page: 1 });
                  }}
                >
                  <input
                    className="input"
                    onChange={(event) => setSearchInput(event.target.value)}
                    placeholder="Search by name, city, phone, email, firm..."
                    value={searchInput}
                  />
                  <button className="button button-secondary" type="submit">
                    Search
                  </button>
                  <button
                    className="button button-secondary"
                    onClick={() => {
                      setSearchInput("");
                      updateParams({ search: "", page: 1 });
                    }}
                    type="button"
                  >
                    Clear
                  </button>
                </form>
              </div>
            </div>

            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Full name</th>
                    <th>Email</th>
                    <th>Phone</th>
                    <th>City</th>
                    <th>Firm</th>
                    <th>Contact</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {data?.avocats.length ? (
                    data.avocats.map((avocat) => (
                      <tr key={avocat.id}>
                        <td>{avocat.fullName}</td>
                        <td>{avocat.email || "-"}</td>
                        <td>{avocat.phone || "-"}</td>
                        <td>{avocat.city || "-"}</td>
                        <td>{avocat.firmName || "-"}</td>
                        <td>{avocat.preferredContactMethod}</td>
                        <td>
                          <div className="row-actions">
                            <button
                              className="button button-secondary"
                              onClick={() => startEdit(avocat)}
                              type="button"
                            >
                              Update
                            </button>
                            <button
                              className="button button-primary"
                              disabled={busyKey !== null}
                              onClick={() =>
                                void runAction(`/api/avocats/${avocat.id}/send`, `send-${avocat.id}`)
                              }
                              type="button"
                            >
                              {busyKey === `send-${avocat.id}` ? "Sending..." : "Send"}
                            </button>
                            <button
                              className="button button-danger"
                              disabled={busyKey !== null}
                              onClick={() =>
                                void runAction(`/api/avocats/${avocat.id}`, `delete-${avocat.id}`, {
                                  method: "DELETE"
                                })
                              }
                              type="button"
                            >
                              {busyKey === `delete-${avocat.id}` ? "Deleting..." : "Delete"}
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))
                  : (
                    <tr>
                      <td colSpan={7} style={{ color: "var(--muted)" }}>
                        {loading ? "Loading..." : "No avocats available for this search."}
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>

            <div className="pager">
              <span className="helper-text">
                Page {data?.pagination.page ?? 1} of {data?.pagination.totalPages ?? 1}
              </span>
              <div className="action-row">
                <button
                  className="button button-secondary"
                  disabled={!data || data.pagination.page <= 1}
                  onClick={() => updateParams({ page: (data?.pagination.page || 1) - 1 })}
                  type="button"
                >
                  Previous
                </button>
                <button
                  className="button button-secondary"
                  disabled={!data || data.pagination.page >= data.pagination.totalPages}
                  onClick={() => updateParams({ page: (data?.pagination.page || 1) + 1 })}
                  type="button"
                >
                  Next
                </button>
              </div>
            </div>
          </div>
        </section>

        <section className="logs-section">
          <div className="table-card glass">
            <div style={{ padding: 18 }}>
              <div className="toolbar">
                <div>
                  <h3>Delivery logs</h3>
                  <p className="helper-text">Filter the status and monitor the latest outreach runs.</p>
                </div>

                <div style={{ minWidth: 220 }}>
                  <label className="label" htmlFor="status-filter">
                    Filter by status
                  </label>
                  <select
                    id="status-filter"
                    className="select"
                    onChange={(event) => updateParams({ status: event.target.value, page: 1 })}
                    value={currentStatus}
                  >
                    <option value="all">All</option>
                    <option value="pending">Pending</option>
                    <option value="sent">Sent</option>
                    <option value="failed">Failed</option>
                  </select>
                </div>
              </div>
            </div>

            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Lawyer name</th>
                    <th>Contact</th>
                    <th>City</th>
                    <th>Campaign</th>
                    <th>Status</th>
                    <th>Attempts</th>
                    <th>Last error</th>
                    <th>Sent date</th>
                  </tr>
                </thead>
                <tbody>
                  {data?.logs.length ? (
                    data.logs.map((log) => (
                      <tr key={log.id}>
                        <td>{log.lawyerName}</td>
                        <td>{log.email}</td>
                        <td>{log.city}</td>
                        <td>{log.campaignName}</td>
                        <td>
                          <span className={`badge badge-${log.status}`}>{log.status}</span>
                        </td>
                        <td>{log.attempts}</td>
                        <td>{log.lastError || "-"}</td>
                        <td>{formatDate(log.sentAt)}</td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={8} style={{ color: "var(--muted)" }}>
                        {loading ? "Loading..." : "No outreach logs available for this filter."}
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </section>
      </main>

      {message ? <p className="status-message">{message}</p> : null}
    </div>
  );
}

"use client";

import { ChangeEvent, FormEvent, useCallback, useEffect, useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, LineChart, Line, ResponsiveContainer } from "recharts";

type DashboardPayload = {
  metrics: {
    totalContacts: number;
    sentCount: number;
    pendingCount: number;
    failedCount: number;
  };
  pagination: {
    page: number;
    pageSize: number;
    totalItems: number;
    totalPages: number;
    search: string;
  };
  analytics: {
    sentByChannel: Array<{ label: string; key: string; count: number }>;
    sentByHour: Array<{ hour: string; count: number }>;
    sentByDay: Array<{ day: string; count: number }>;
    sentByWeek: Array<{ week: string; count: number }>;
    sentByCity: Array<{ city: string; count: number }>;
  };
  avocats: Array<{
    id: string;
    fullName: string;
    email: string | null;
    phone: string | null;
    city: string | null;
    firmName: string | null;
    preferredContactMethod: "email" | "whatsapp" | "both";
  }>;
  logs: Array<{
    id: string;
    lawyerName: string;
    email: string;
    status: "pending" | "sent" | "failed";
    attempts: number;
    lastError: string | null;
    sentAt: string | null;
    campaignName: string;
    city: string;
  }>;
};

type ApiResult = {
  message?: string;
  processed?: number;
  sent?: number;
  failed?: number;
  resetCount?: number;
  created?: number;
  skipped?: number;
  errors?: string[];
};

type FormState = {
  full_name: string;
  email: string;
  phone: string;
  city: string;
  firm_name: string;
  preferred_contact_method: "email" | "whatsapp" | "both";
};

const emptyForm: FormState = {
  full_name: "",
  email: "",
  phone: "",
  city: "",
  firm_name: "",
  preferred_contact_method: "email"
};

function formatDate(value: string | null) {
  if (!value) {
    return "-";
  }

  return new Intl.DateTimeFormat("fr-FR", {
    dateStyle: "medium",
    timeStyle: "short"
  }).format(new Date(value));
}

export function DashboardClient() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const currentStatus = searchParams.get("status") || "all";
  const currentSearch = searchParams.get("search") || "";
  const currentPage = Number(searchParams.get("page") || "1");
  const [data, setData] = useState<DashboardPayload | null>(null);
  const [loading, setLoading] = useState(true);
  const [busyKey, setBusyKey] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);
  const [form, setForm] = useState<FormState>(emptyForm);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [searchInput, setSearchInput] = useState(currentSearch);

  const loadDashboard = useCallback(async () => {
    setLoading(true);

    try {
      const params = new URLSearchParams();

      if (currentStatus !== "all") {
        params.set("status", currentStatus);
      }

      if (currentSearch) {
        params.set("search", currentSearch);
      }

      if (currentPage > 1) {
        params.set("page", String(currentPage));
      }

      const response = await fetch(`/api/dashboard${params.toString() ? `?${params.toString()}` : ""}`, {
        cache: "no-store"
      });

      if (!response.ok) {
        throw new Error("Unable to load dashboard data.");
      }

      const payload = (await response.json()) as DashboardPayload;
      setData(payload);
    } catch (error) {
      setMessage(error instanceof Error ? error.message : "Unable to load dashboard data.");
    } finally {
      setLoading(false);
    }
  }, [currentPage, currentSearch, currentStatus]);

  useEffect(() => {
    void loadDashboard();
  }, [loadDashboard]);

  useEffect(() => {
    setSearchInput(currentSearch);
  }, [currentSearch]);

  function updateParams(next: { status?: string; search?: string; page?: number }) {
    const params = new URLSearchParams(searchParams.toString());

    if (next.status !== undefined) {
      if (next.status === "all") {
        params.delete("status");
      } else {
        params.set("status", next.status);
      }
    }

    if (next.search !== undefined) {
      if (next.search.trim()) {
        params.set("search", next.search.trim());
      } else {
        params.delete("search");
      }
    }

    if (next.page !== undefined) {
      if (next.page > 1) {
        params.set("page", String(next.page));
      } else {
        params.delete("page");
      }
    }

    router.replace(`/dashboard${params.toString() ? `?${params.toString()}` : ""}`);
  }

  function onFormChange(event: ChangeEvent<HTMLInputElement | HTMLSelectElement>) {
    const { name, value } = event.target;
    setForm((current) => ({ ...current, [name]: value }));
  }

  function resetForm() {
    setForm(emptyForm);
    setEditingId(null);
  }

  async function runAction(path: string, actionKey: string, options?: { method?: string; body?: unknown }) {
    setBusyKey(actionKey);
    setMessage(null);

    try {
      const response = await fetch(path, {
        method: options?.method || "POST",
        headers: options?.body
          ? {
              "Content-Type": "application/json"
            }
          : undefined,
        body: options?.body ? JSON.stringify(options.body) : undefined
      });

      const payload = (await response.json()) as ApiResult & { error?: string };

      if (!response.ok) {
        throw new Error(payload.error || "Request failed.");
      }

      if (actionKey === "logout") {
        router.replace("/login");
        router.refresh();
        return true;
      }

      setMessage(payload.message || "Action completed successfully.");
      await loadDashboard();
      return true;
    } catch (error) {
      setMessage(error instanceof Error ? error.message : "Request failed.");
      return false;
    } finally {
      setBusyKey(null);
    }
  }

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();

    let success: boolean;

    if (editingId) {
      success = await runAction(`/api/avocats/${editingId}`, "save-avocat", {
        method: "PUT",
        body: form
      });
    } else {
      success = await runAction("/api/avocats", "add-avocat", {
        method: "POST",
        body: form
      });
    }

    if (success) {
      resetForm();
    }
  }

  async function handleImport(event: ChangeEvent<HTMLInputElement>) {
    const file = event.target.files?.[0];

    if (!file) {
      return;
    }

    setBusyKey("import");
    setMessage(null);

    try {
      const fileText = await file.text();
      const payload = JSON.parse(fileText) as unknown;
      const response = await fetch("/api/avocats/import", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(payload)
      });
      const result = (await response.json()) as ApiResult & { error?: string };

      if (!response.ok) {
        throw new Error(result.error || "Unable to import avocats.");
      }

      const importMessage = [result.message, result.errors?.slice(0, 3).join(" | ")]
        .filter(Boolean)
        .join(" ");
      setMessage(importMessage);
      await loadDashboard();
    } catch (error) {
      setMessage(error instanceof Error ? error.message : "Unable to import avocats.");
    } finally {
      event.target.value = "";
      setBusyKey(null);
    }
  }

  async function handleExport() {
    setBusyKey("export");
    setMessage(null);

    try {
      const response = await fetch("/api/avocats/export", {
        method: "GET"
      });

      if (!response.ok) {
        const payload = (await response.json()) as { error?: string };
        throw new Error(payload.error || "Unable to export avocats.");
      }

      const blob = await response.blob();
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = "avocats-export.json";
      document.body.appendChild(link);
      link.click();
      link.remove();
      URL.revokeObjectURL(url);
      setMessage("Avocats exported successfully.");
    } catch (error) {
      setMessage(error instanceof Error ? error.message : "Unable to export avocats.");
    } finally {
      setBusyKey(null);
    }
  }

  function startEdit(avocat: DashboardPayload["avocats"][number]) {
    setEditingId(avocat.id);
    setForm({
      full_name: avocat.fullName,
      email: avocat.email || "",
      phone: avocat.phone || "",
      city: avocat.city || "",
      firm_name: avocat.firmName || "",
      preferred_contact_method: avocat.preferredContactMethod
    });
  }

  return (
    <div className="dashboard-layout">
      <header className="dashboard-nav">
        <div className="nav-brand">
          <h1 className="page-title">Outreach Dashboard 2026</h1>
          <span className="hero-note">AI-Powered Campaign Management</span>
        </div>
        <div className="nav-actions">
          <button
            className="button button-secondary"
            disabled={loading}
            onClick={() => void loadDashboard()}
            type="button"
          >
            {loading ? "Refreshing..." : "Refresh"}
          </button>
          <button
            className="button button-primary"
            disabled={busyKey !== null}
            onClick={() => void runAction("/api/send", "send")}
            type="button"
          >
            {busyKey === "send" ? "Sending..." : "Send Now"}
          </button>
          <button
            className="button button-danger"
            disabled={busyKey !== null}
            onClick={() => void runAction("/api/retry-failed", "retry")}
            type="button"
          >
            {busyKey === "retry" ? "Retrying..." : "Retry Failed"}
          </button>
          <button
            className="button button-secondary"
            disabled={busyKey !== null}
            onClick={() => void runAction("/api/auth/logout", "logout")}
            type="button"
          >
            {busyKey === "logout" ? "Logging out..." : "Logout"}
          </button>
        </div>
      </header>

      <main className="dashboard-main">
        <section className="metrics-section">
          <h2 className="section-title">Key Metrics</h2>
          <div className="metrics-grid">
            <article className="metric-card glass">
              <p className="metric-label">Total contacts</p>
              <h2 className="metric-value">{data?.metrics.totalContacts ?? "-"}</h2>
            </article>
            <article className="metric-card glass">
              <p className="metric-label">Sent</p>
              <h2 className="metric-value">{data?.metrics.sentCount ?? "-"}</h2>
            </article>
            <article className="metric-card glass">
              <p className="metric-label">Pending</p>
              <h2 className="metric-value">{data?.metrics.pendingCount ?? "-"}</h2>
            </article>
            <article className="metric-card glass">
              <p className="metric-label">Failed</p>
              <h2 className="metric-value">{data?.metrics.failedCount ?? "-"}</h2>
            </article>
          </div>
        </section>

        <section className="analytics-section">
          <h2 className="section-title">Analytics</h2>
          <div className="charts-grid">
            <article className="chart-card glass">
              <h3>Sent by Channel</h3>
              <div className="chart-container">
                <ResponsiveContainer width="100%" height={300}>
                  <PieChart>
                    <Pie
                      data={data?.analytics.sentByChannel || []}
                      cx="50%"
                      cy="50%"
                      labelLine={false}
                      outerRadius={80}
                      fill="#8884d8"
                      dataKey="count"
                    >
                      {data?.analytics.sentByChannel.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={['#007bff', '#28a745', '#ffc107'][index % 3]} />
                      ))}
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </article>

            <article className="chart-card glass">
              <h3>Sent by Hour</h3>
              <div className="chart-container">
                <ResponsiveContainer width="100%" height={300}>
                  <LineChart data={data?.analytics.sentByHour || []}>
                    <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                    <XAxis dataKey="hour" stroke="var(--muted)" />
                    <YAxis stroke="var(--muted)" />
                    <Tooltip contentStyle={{ backgroundColor: 'var(--bg-elevated)', border: '1px solid var(--border)' }} />
                    <Line type="monotone" dataKey="count" stroke="#007bff" strokeWidth={2} dot={{ fill: '#007bff' }} />
                  </LineChart>
                </ResponsiveContainer>
              </div>
            </article>

            <article className="chart-card glass">
              <h3>Sent by Day</h3>
              <div className="chart-container">
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={data?.analytics.sentByDay || []}>
                    <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                    <XAxis dataKey="day" stroke="var(--muted)" />
                    <YAxis stroke="var(--muted)" />
                    <Tooltip contentStyle={{ backgroundColor: 'var(--bg-elevated)', border: '1px solid var(--border)' }} />
                    <Bar dataKey="count" fill="#007bff" />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </article>

            <article className="chart-card glass">
              <h3>Sent by Week</h3>
              <div className="chart-container">
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={data?.analytics.sentByWeek || []}>
                    <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                    <XAxis dataKey="week" stroke="var(--muted)" />
                    <YAxis stroke="var(--muted)" />
                    <Tooltip contentStyle={{ backgroundColor: 'var(--bg-elevated)', border: '1px solid var(--border)' }} />
                    <Bar dataKey="count" fill="#28a745" />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </article>

            <article className="chart-card glass">
              <h3>Sent by City</h3>
              <div className="chart-container">
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={data?.analytics.sentByCity || []} layout="horizontal">
                    <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                    <XAxis type="number" stroke="var(--muted)" />
                    <YAxis dataKey="city" type="category" stroke="var(--muted)" width={80} />
                    <Tooltip contentStyle={{ backgroundColor: 'var(--bg-elevated', border: '1px solid var(--border)' }} />
                    <Bar dataKey="count" fill="#ffc107" />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </article>
          </div>
        </section>

        <section className="management-section">
          <h2 className="section-title">Contact Management</h2>
          <div className="panel-grid">
            <article className="panel-card glass">
              <h3>{editingId ? "Update avocat" : "Add avocat"}</h3>
              <p className="helper-text">
                Manage one contact at a time here, or use JSON import/export for bulk operations.
              </p>

              <form className="form-grid" onSubmit={handleSubmit} style={{ marginTop: 18 }}>
                <div className="full-span">
                  <label className="label" htmlFor="full_name">
                    Full name
                  </label>
                  <input
                    id="full_name"
                    className="input"
                    name="full_name"
                    onChange={onFormChange}
                    required
                    value={form.full_name}
                  />
                </div>

                <div>
                  <label className="label" htmlFor="email">
                    Email
                  </label>
                  <input
                    id="email"
                    className="input"
                    name="email"
                    onChange={onFormChange}
                    type="email"
                    value={form.email}
                  />
                </div>

                <div>
                  <label className="label" htmlFor="phone">
                    Phone
                  </label>
                  <input
                    id="phone"
                    className="input"
                    name="phone"
                    onChange={onFormChange}
                    value={form.phone}
                  />
                </div>

                <div>
                  <label className="label" htmlFor="city">
                    City
                  </label>
                  <input
                    id="city"
                    className="input"
                    name="city"
                    onChange={onFormChange}
                    value={form.city}
                  />
                </div>

                <div>
                  <label className="label" htmlFor="firm_name">
                    Firm name
                  </label>
                  <input
                    id="firm_name"
                    className="input"
                    name="firm_name"
                    onChange={onFormChange}
                    value={form.firm_name}
                  />
                </div>

                <div className="full-span">
                  <label className="label" htmlFor="preferred_contact_method">
                    Preferred contact
                  </label>
                  <select
                    id="preferred_contact_method"
                    className="select"
                    name="preferred_contact_method"
                    onChange={onFormChange}
                    value={form.preferred_contact_method}
                  >
                    <option value="email">email</option>
                    <option value="whatsapp">whatsapp</option>
                    <option value="both">both</option>
                  </select>
                </div>

                <div className="full-span action-row" style={{ marginTop: 8 }}>
                  <button className="button button-primary" disabled={busyKey !== null} type="submit">
                    {busyKey === "add-avocat" || busyKey === "save-avocat"
                      ? "Saving..."
                      : editingId
                        ? "Update avocat"
                        : "Add avocat"}
                  </button>
                  {editingId ? (
                    <button className="button button-secondary" onClick={resetForm} type="button">
                      Cancel edit
                    </button>
                  ) : null}
                </div>
              </form>
            </article>

            <article className="panel-card glass">
              <h3>Import / export JSON</h3>
              <p className="helper-text">
                Import Apify raw JSON or export the current avocat list.
              </p>

              <div className="action-row" style={{ marginTop: 18 }}>
                <label className="button button-secondary" htmlFor="avocat-import">
                  {busyKey === "import" ? "Importing..." : "Import JSON"}
                </label>
                <input
                  id="avocat-import"
                  accept=".json,application/json"
                  className="file-input"
                  disabled={busyKey !== null}
                  onChange={handleImport}
                  style={{ display: "none" }}
                  type="file"
                />
                <button
                  className="button button-secondary"
                  disabled={busyKey !== null}
                  onClick={() => void handleExport()}
                  type="button"
                >
                  {busyKey === "export" ? "Exporting..." : "Export JSON"}
                </button>
              </div>

              <p className="helper-text" style={{ marginTop: 16 }}>
                Use the searchable table below to update, delete, or send outreach for a specific
                avocat.
              </p>
            </article>
          </div>
        </section>

        <section className="contacts-section">
          <div className="table-card glass">
            <div style={{ padding: 18 }}>
              <div className="toolbar">
                <div>
                  <h3>Avocats</h3>
                  <p className="helper-text">{data?.pagination.totalItems ?? 0} contact(s) found.</p>
                </div>

                <form
                  className="search-row"
                  onSubmit={(event) => {
                    event.preventDefault();
                    updateParams({ search: searchInput, page: 1 });
                  }}
                >
                  <input
                    className="input"
                    onChange={(event) => setSearchInput(event.target.value)}
                    placeholder="Search by name, city, phone, email, firm..."
                    value={searchInput}
                  />
                  <button className="button button-secondary" type="submit">
                    Search
                  </button>
                  <button
                    className="button button-secondary"
                    onClick={() => {
                      setSearchInput("");
                      updateParams({ search: "", page: 1 });
                    }}
                    type="button"
                  >
                    Clear
                  </button>
                </form>
              </div>
            </div>

            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Full name</th>
                    <th>Email</th>
                    <th>Phone</th>
                    <th>City</th>
                    <th>Firm</th>
                    <th>Contact</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {data?.avocats.length ? (
                    data.avocats.map((avocat) => (
                      <tr key={avocat.id}>
                        <td>{avocat.fullName}</td>
                        <td>{avocat.email || "-"}</td>
                        <td>{avocat.phone || "-"}</td>
                        <td>{avocat.city || "-"}</td>
                        <td>{avocat.firmName || "-"}</td>
                        <td>{avocat.preferredContactMethod}</td>
                        <td>
                          <div className="row-actions">
                            <button
                              className="button button-secondary"
                              onClick={() => startEdit(avocat)}
                              type="button"
                            >
                              Update
                            </button>
                            <button
                              className="button button-primary"
                              disabled={busyKey !== null}
                              onClick={() =>
                                void runAction(`/api/avocats/${avocat.id}/send`, `send-${avocat.id}`)
                              }
                              type="button"
                            >
                              {busyKey === `send-${avocat.id}` ? "Sending..." : "Send"}
                            </button>
                            <button
                              className="button button-danger"
                              disabled={busyKey !== null}
                              onClick={() =>
                                void runAction(`/api/avocats/${avocat.id}`, `delete-${avocat.id}`, {
                                  method: "DELETE"
                                })
                              }
                              type="button"
                            >
                              {busyKey === `delete-${avocat.id}` ? "Deleting..." : "Delete"}
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))
                  : (
                    <tr>
                      <td colSpan={7} style={{ color: "var(--muted)" }}>
                        {loading ? "Loading..." : "No avocats available for this search."}
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>

            <div className="pager">
              <span className="helper-text">
                Page {data?.pagination.page ?? 1} of {data?.pagination.totalPages ?? 1}
              </span>
              <div className="action-row">
                <button
                  className="button button-secondary"
                  disabled={!data || data.pagination.page <= 1}
                  onClick={() => updateParams({ page: (data?.pagination.page || 1) - 1 })}
                  type="button"
                >
                  Previous
                </button>
                <button
                  className="button button-secondary"
                  disabled={!data || data.pagination.page >= data.pagination.totalPages}
                  onClick={() => updateParams({ page: (data?.pagination.page || 1) + 1 })}
                  type="button"
                >
                  Next
                </button>
              </div>
            </div>
          </div>
        </section>

        <section className="logs-section">
          <div className="table-card glass">
            <div style={{ padding: 18 }}>
              <div className="toolbar">
                <div>
                  <h3>Delivery logs</h3>
                  <p className="helper-text">Filter the status and monitor the latest outreach runs.</p>
                </div>

                <div style={{ minWidth: 220 }}>
                  <label className="label" htmlFor="status-filter">
                    Filter by status
                  </label>
                  <select
                    id="status-filter"
                    className="select"
                    onChange={(event) => updateParams({ status: event.target.value, page: 1 })}
                    value={currentStatus}
                  >
                    <option value="all">All</option>
                    <option value="pending">Pending</option>
                    <option value="sent">Sent</option>
                    <option value="failed">Failed</option>
                  </select>
                </div>
              </div>
            </div>

            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Lawyer name</th>
                    <th>Contact</th>
                    <th>City</th>
                    <th>Campaign</th>
                    <th>Status</th>
                    <th>Attempts</th>
                    <th>Last error</th>
                    <th>Sent date</th>
                  </tr>
                </thead>
                <tbody>
                  {data?.logs.length ? (
                    data.logs.map((log) => (
                      <tr key={log.id}>
                        <td>{log.lawyerName}</td>
                        <td>{log.email}</td>
                        <td>{log.city}</td>
                        <td>{log.campaignName}</td>
                        <td>
                          <span className={`badge badge-${log.status}`}>{log.status}</span>
                        </td>
                        <td>{log.attempts}</td>
                        <td>{log.lastError || "-"}</td>
                        <td>{formatDate(log.sentAt)}</td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={8} style={{ color: "var(--muted)" }}>
                        {loading ? "Loading..." : "No outreach logs available for this filter."}
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </section>
      </main>

      {message ? <p className="status-message">{message}</p> : null}
    </div>
  );
}

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  /* Color Palette - Elegant & Sophisticated */
  --bg: #fafaf8;
  --bg-secondary: #f5f3f0;
  --bg-elevated: #ffffff;
  --bg-card: #ffffff;
  --border: #ede9e2;
  --border-light: #f5f1eb;
  --text: #1f1f1f;
  --text-secondary: #666666;
  --text-muted: #999999;
  --accent: #6b4423;
  --accent-light: #8b5d3f;
  --accent-strong: #4a2612;

  /* Status Colors */
  --success: #2d6a4f;
  --warning: #9b6f47;
  --danger: #8b3a3a;
  --info: #4a5859;

  /* Shadows - Refined */
  --shadow-xs: 0 1px 2px rgba(31, 31, 31, 0.04);
  --shadow-sm: 0 2px 4px rgba(31, 31, 31, 0.08);
  --shadow-md: 0 4px 12px rgba(31, 31, 31, 0.1);
  --shadow-lg: 0 12px 32px rgba(31, 31, 31, 0.12);
  --shadow-xl: 0 20px 48px rgba(31, 31, 31, 0.15);

  /* Gradients - Sophisticated */
  --gradient: linear-gradient(135deg, #6b4423 0%, #8b5d3f 100%);
  --gradient-accent: linear-gradient(135deg, #4a2612 0%, #6b4423 100%);
  --gradient-success: linear-gradient(135deg, #2d6a4f 0%, #3d8a5f 100%);
  --gradient-warning: linear-gradient(135deg, #9b6f47 0%, #b08557 100%);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  min-height: 100%;
}

body {
  background:
    radial-gradient(circle at 15% 50%, rgba(107, 68, 35, 0.08), transparent 50%),
    radial-gradient(circle at 85% 85%, rgba(107, 68, 35, 0.06), transparent 50%),
    var(--bg);
  color: var(--text);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  line-height: 1.6;
}

a {
  color: inherit;
  text-decoration: none;
}

button,
input,
select,
textarea {
  font: inherit;
}

/* ==================== Typography ==================== */

.page-title {
  margin: 0;
  font-size: clamp(1.8rem, 3vw, 2.8rem);
  font-weight: 700;
  line-height: 1.2;
  letter-spacing: -0.02em;
  color: var(--text);
}

.page-subtitle {
  margin: 8px 0 0;
  color: var(--text-muted);
  font-size: 0.95rem;
  font-weight: 500;
}

.section-title {
  margin: 0 0 28px;
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--text);
  letter-spacing: -0.01em;
}

.section-subtitle {
  color: var(--text-secondary);
  font-size: 0.95rem;
  font-weight: 500;
  margin-top: 8px;
}

/* ==================== Layout ==================== */

.shell {
  min-height: 100vh;
  padding: 32px 20px 48px;
}

.container {
  max-width: 1400px;
  margin: 0 auto;
}

.dashboard-layout {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

.dashboard-nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 20px 32px;
  background: rgba(255, 255, 255, 0.95);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--border-light);
  box-shadow: var(--shadow-xs);
  position: sticky;
  top: 0;
  z-index: 40;
}

.nav-brand {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.nav-brand .page-title {
  margin: 0;
  font-size: 1.6rem;
  font-weight: 700;
  color: var(--accent-strong);
  letter-spacing: -0.02em;
}

.nav-actions {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.dashboard-main {
  flex: 1;
  padding: 48px 32px;
  display: flex;
  flex-direction: column;
  gap: 56px;
}

/* ==================== Sections ==================== */

.metrics-section,
.analytics-section,
.management-section,
.contacts-section,
.logs-section {
  width: 100%;
}

.metrics-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 20px;
  margin: 0;
}

.metric-card {
  border-radius: 20px;
  padding: 28px;
  background: #000000;
  color: white;
  box-shadow: var(--shadow-md);
  transition: all 300ms cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
  overflow: hidden;
}

.metric-card::before {
  content: '';
  position: absolute;
  top: -50%;
  right: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle, rgba(255, 255, 255, 0.08), transparent);
  pointer-events: none;
}

.metric-card:hover {
  transform: translateY(-6px);
  box-shadow: var(--shadow-lg);
}

.metric-label {
  margin: 0;
  color: white;
  font-size: 1.1rem;
  font-weight: 600;
  letter-spacing: 0.02em;
  text-transform: uppercase;
}

.metric-value {
  margin: 12px 0 0;
  font-size: clamp(1.8rem, 3vw, 2.6rem);
  font-weight: 700;
  line-height: 1;
}

/* ==================== Buttons ==================== */

.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border: 0;
  border-radius: 12px;
  padding: 10px 18px;
  cursor: pointer;
  transition: all 200ms cubic-bezier(0.4, 0, 0.2, 1);
  font-family: inherit;
  font-weight: 600;
  font-size: 0.9rem;
  letter-spacing: 0.02em;
  white-space: nowrap;
  user-select: none;
}

.button:hover:not(:disabled) {
  transform: translateY(-2px);
}

.button:active:not(:disabled) {
  transform: translateY(0);
}

.button:disabled {
  cursor: not-allowed;
  opacity: 0.6;
}

.button-primary {
  background: var(--gradient);
  color: white;
  box-shadow: 0 4px 12px rgba(107, 68, 35, 0.25);
}

.button-primary:hover:not(:disabled) {
  box-shadow: 0 8px 20px rgba(107, 68, 35, 0.35);
}

.button-secondary {
  background: var(--bg-secondary);
  color: var(--accent-strong);
  border: 1.5px solid var(--border);
}

.button-secondary:hover:not(:disabled) {
  background: var(--border-light);
  border-color: var(--accent);
}

.button-danger {
  background: rgba(139, 58, 58, 0.1);
  color: var(--danger);
  border: 1.5px solid rgba(139, 58, 58, 0.2);
}

.button-danger:hover:not(:disabled) {
  background: rgba(139, 58, 58, 0.15);
  border-color: var(--danger);
}

/* ==================== Forms ==================== */

.label {
  display: block;
  margin-bottom: 10px;
  color: var(--text);
  font-size: 0.9rem;
  font-weight: 600;
  letter-spacing: 0.01em;
}

.input,
.select,
textarea {
  width: 100%;
  border: 1.5px solid var(--border);
  border-radius: 12px;
  padding: 12px 14px;
  background: var(--bg-card);
  color: var(--text);
  font-family: inherit;
  transition: all 200ms ease;
  font-size: 0.95rem;
}

.input:focus,
.select:focus,
textarea:focus {
  outline: none;
  border-color: var(--accent);
  background: white;
  box-shadow: 0 0 0 3px rgba(107, 68, 35, 0.1);
}

textarea {
  resize: vertical;
  min-height: 100px;
}

.form-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 16px;
}

.full-span {
  grid-column: 1 / -1;
}

.action-row {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  align-items: center;
}

.search-row {
  display: flex;
  gap: 12px;
  align-items: center;
  width: min(100%, 680px);
}

.auth-grid {
  display: grid;
  min-height: calc(100vh - 80px);
  align-items: center;
}

.auth-card {
  max-width: 460px;
  border-radius: 30px;
  padding: 34px;
}

.auth-form {
  display: grid;
  gap: 18px;
  margin-top: 28px;
}

.hero-note {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  border-radius: 12px;
  background: rgba(107, 68, 35, 0.08);
  color: var(--accent-strong);
  padding: 8px 12px;
  font-family: inherit;
  font-size: 0.85rem;
  font-weight: 600;
  border: 1px solid rgba(107, 68, 35, 0.15);
  letter-spacing: 0.01em;
}

/* ==================== Cards ==================== */

.glass {
  background: rgba(255, 255, 255, 0.98);
  border: 1px solid var(--border-light);
  box-shadow: var(--shadow-sm);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
}

.panel-card {
  border-radius: 16px;
  padding: 28px;
  background: var(--bg-elevated);
  border: 1px solid var(--border-light);
  box-shadow: var(--shadow-sm);
  transition: all 300ms ease;
}

.panel-card:hover {
  box-shadow: var(--shadow-md);
}

.panel-card h3 {
  margin: 0 0 8px;
  font-size: 1.15rem;
  font-weight: 700;
  color: var(--text);
}

.table-wrap {
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th,
td {
  text-align: left;
  padding: 16px 18px;
  border-bottom: 1px solid var(--border-light);
  font-family: inherit;
  vertical-align: middle;
}

th {
  font-size: 0.8rem;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  color: var(--text-muted);
  font-weight: 700;
  background: var(--bg-secondary);
}

tbody tr {
  transition: background 200ms ease;
}

tbody tr:hover {
  background: var(--bg-secondary);
}

.row-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

/* ==================== Badges ==================== */

.badge {
  display: inline-flex;
  align-items: center;
  border-radius: 8px;
  padding: 6px 12px;
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

.badge-sent {
  color: var(--success);
  background: rgba(45, 106, 79, 0.12);
  border: 1px solid rgba(45, 106, 79, 0.25);
}

.badge-pending {
  color: var(--warning);
  background: rgba(155, 111, 71, 0.12);
  border: 1px solid rgba(155, 111, 71, 0.25);
}

.badge-failed {
  color: var(--danger);
  background: rgba(139, 58, 58, 0.12);
  border: 1px solid rgba(139, 58, 58, 0.25);
}

.badge-info {
  color: var(--info);
  background: rgba(74, 88, 89, 0.12);
  border: 1px solid rgba(74, 88, 89, 0.25);
}

/* ==================== Status Messages & Alerts ==================== */

.status-message {
  position: fixed;
  bottom: 24px;
  right: 24px;
  max-width: 420px;
  border-radius: 16px;
  padding: 16px 20px;
  background: var(--bg-elevated);
  border: 1px solid var(--border-light);
  box-shadow: var(--shadow-xl);
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--text);
  animation: slideInUp 300ms cubic-bezier(0.4, 0, 0.2, 1);
  z-index: 50;
}

.status-message.error {
  border-left: 4px solid var(--danger);
  background: rgba(139, 58, 58, 0.05);
  color: var(--danger);
}

.status-message.success {
  border-left: 4px solid var(--success);
  background: rgba(45, 106, 79, 0.05);
  color: var(--success);
}

.status-message.warning {
  border-left: 4px solid var(--warning);
  background: rgba(155, 111, 71, 0.05);
  color: var(--warning);
}

.status-message.info {
  border-left: 4px solid var(--info);
  background: rgba(74, 88, 89, 0.05);
  color: var(--info);
}

@keyframes slideInUp {
  from {
    transform: translateY(100px);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}

/* ==================== Modals ==================== */

.modal-backdrop {
  position: fixed;
  inset: 0;
  background: rgba(31, 31, 31, 0.4);
  backdrop-filter: blur(4px);
  animation: fadeIn 200ms ease;
  z-index: 50;
}

.modal {
  position: fixed;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  max-width: 500px;
  width: 90%;
  border-radius: 20px;
  background: var(--bg-elevated);
  border: 1px solid var(--border-light);
  box-shadow: var(--shadow-xl);
  animation: modalSlideIn 300ms cubic-bezier(0.4, 0, 0.2, 1);
  z-index: 51;
}

.modal-header {
  padding: 28px;
  border-bottom: 1px solid var(--border-light);
}

.modal-header h2 {
  margin: 0;
  font-size: 1.3rem;
  font-weight: 700;
  color: var(--text);
}

.modal-body {
  padding: 28px;
}

.modal-footer {
  padding: 20px 28px;
  border-top: 1px solid var(--border-light);
  display: flex;
  gap: 12px;
  justify-content: flex-end;
  background: var(--bg-secondary);
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes modalSlideIn {
  from {
    transform: translate(-50%, -50%) scale(0.95);
    opacity: 0;
  }
  to {
    transform: translate(-50%, -50%) scale(1);
    opacity: 1;
  }
}

/* ==================== Utilities ==================== */

.toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 16px;
  margin-bottom: 24px;
}

.helper-text {
  margin: 10px 0 0;
  color: var(--text-muted);
  font-family: inherit;
  font-size: 0.9rem;
}

.pager {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 16px;
  padding: 20px 28px;
  border-top: 1px solid var(--border-light);
  background: var(--bg-secondary);
}

.panel-grid {
  display: grid;
  grid-template-columns: minmax(380px, 450px) minmax(0, 1fr);
  gap: 24px;
  margin-bottom: 0;
}

.file-input {
  width: 100%;
  font-family: inherit;
}

.mini-stat {
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 16px;
  background: var(--bg-card);
  transition: all 200ms ease;
}

.mini-stat:hover {
  border-color: var(--accent);
  box-shadow: var(--shadow-sm);
}

/* ==================== Charts ==================== */

.charts-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(440px, 1fr));
  gap: 24px;
  margin-bottom: 0;
}

.chart-card {
  border-radius: 16px;
  padding: 28px;
  background: var(--bg-elevated);
  border: 1px solid var(--border-light);
  box-shadow: var(--shadow-sm);
  min-height: 400px;
  transition: all 300ms ease;
}

.chart-card:hover {
  box-shadow: var(--shadow-md);
  transform: translateY(-2px);
}

.chart-card h3 {
  margin: 0 0 20px;
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--text);
  letter-spacing: -0.01em;
}

.chart-container {
  width: 100%;
  height: 300px;
}

/* ==================== Responsive ==================== */

@media (max-width: 1100px) {
  .charts-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .panel-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 980px) {
  .metrics-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .dashboard-main {
    padding: 32px 24px;
    gap: 40px;
  }

  .toolbar,
  .search-row,
  .pager {
    flex-direction: column;
    align-items: stretch;
  }
}

@media (max-width: 768px) {
  .dashboard-nav {
    flex-direction: column;
    gap: 16px;
    align-items: flex-start;
  }

  .nav-actions {
    width: 100%;
    justify-content: flex-start;
  }

  .charts-grid {
    grid-template-columns: 1fr;
  }

  .panel-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 640px) {
  .metrics-grid,
  .form-grid {
    grid-template-columns: 1fr;
  }

  .dashboard-main {
    padding: 24px 16px;
    gap: 32px;
  }

  .dashboard-nav {
    padding: 16px;
  }

  .button {
    padding: 10px 14px;
    font-size: 0.85rem;
  }

  .table-card {
    border-radius: 12px;
  }

  .modal {
    width: 95%;
  }

  .status-message {
    width: calc(100% - 32px);
    right: 16px;
    left: 16px;
  }
}

